import type * as React from 'react';
import { Radio as RadioPrimitive } from '@base-ui/react/radio';
import { RadioGroup as RadioGroupPrimitive } from '@base-ui/react/radio-group';
import { forwardRef, useState } from 'react';
import { RatingStarIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Rating.module.css';

type RatingSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';

type RatingProps = Omit<
  React.ComponentPropsWithoutRef<typeof RadioGroupPrimitive>,
  'children' | 'defaultValue' | 'orientation' | 'onValueChange' | 'value'
> & {
  defaultValue?: number;
  max?: number;
  onValueChange?: (value: number) => void;
  size?: RatingSize;
  value?: number;
};

const DEFAULT_MAX = 5;

const Rating = forwardRef<React.ComponentRef<typeof RadioGroupPrimitive>, RatingProps>(
  function Rating(
    {
      className,
      defaultValue,
      disabled,
      max = DEFAULT_MAX,
      onValueChange,
      readOnly,
      size = 'md',
      value,
      ...props
    },
    ref,
  ) {
    const normalizedMax = normalizeMax(max);
    const [uncontrolledValue, setUncontrolledValue] = useState<number | undefined>(() =>
      normalizeRatingValue(defaultValue, normalizedMax),
    );
    const currentValue = normalizeRatingValue(value ?? uncontrolledValue, normalizedMax);

    const handleValueChange = (nextValue: string | number) => {
      const normalizedValue = normalizeRatingValue(Number(nextValue), normalizedMax);

      if (normalizedValue == null) {
        return;
      }

      if (value === undefined) {
        setUncontrolledValue(normalizedValue);
      }

      onValueChange?.(normalizedValue);
    };

    return (
      <RadioGroupPrimitive
        ref={ref}
        data-slot="rating-root"
        data-size={size}
        className={mergeClassName(className, styles.root)}
        disabled={disabled}
        onValueChange={handleValueChange}
        readOnly={readOnly}
        value={currentValue?.toString()}
        {...props}
      >
        {Array.from({ length: normalizedMax }, (_, index) => {
          const ratingValue = index + 1;
          const isFilled = currentValue != null && ratingValue <= currentValue;

          return (
            <RadioPrimitive.Root
              key={ratingValue}
              aria-label={
                readOnly
                  ? `${ratingValue} out of ${normalizedMax}`
                  : `Rate ${ratingValue} out of ${normalizedMax}`
              }
              data-empty={isFilled ? undefined : ''}
              data-filled={isFilled ? '' : undefined}
              data-slot="rating-item"
              className={styles.item}
              disabled={disabled}
              readOnly={readOnly}
              value={ratingValue.toString()}
            >
              <RatingStarIcon data-slot="rating-icon" className={styles.icon} />
            </RadioPrimitive.Root>
          );
        })}
      </RadioGroupPrimitive>
    );
  },
);

function normalizeMax(max: number) {
  if (!Number.isFinite(max)) {
    return DEFAULT_MAX;
  }

  return Math.max(1, Math.floor(max));
}

function normalizeRatingValue(value: number | undefined, max: number) {
  if (value == null || !Number.isFinite(value)) {
    return undefined;
  }

  const normalizedValue = Math.floor(value);

  if (normalizedValue < 1) {
    return undefined;
  }

  return Math.min(normalizedValue, max);
}

export { Rating };
export type { RatingProps, RatingSize };

@layer ui.components {
  .root {
    display: inline-flex;
    align-items: center;
    gap: var(--rating-gap, var(--spacing-1));
    color: var(--rating-color, var(--color-muted-foreground));

    &[data-disabled] {
      opacity: var(--rating-disabled-opacity, var(--opacity-disabled));
    }

    &[data-size='xs'] {
      --_rating-icon-size: var(--rating-icon-size-xs, 0.875rem);
    }

    &[data-size='sm'] {
      --_rating-icon-size: var(--rating-icon-size-sm, 1rem);
    }

    &[data-size='md'] {
      --_rating-icon-size: var(--rating-icon-size-md, 1.25rem);
    }

    &[data-size='lg'] {
      --_rating-icon-size: var(--rating-icon-size-lg, 1.5rem);
    }

    &[data-size='xl'] {
      --_rating-icon-size: var(--rating-icon-size-xl, 1.75rem);
    }
  }

  .item {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin: 0;
    border: 0;
    border-radius: var(--radius-sm);
    padding: 0;
    background-color: transparent;
    color: inherit;
    line-height: 0;
    cursor: pointer;
    transition:
      color var(--rating-transition, var(--transition-default)),
      opacity var(--rating-transition, var(--transition-default));

    &[data-filled] {
      color: var(--rating-active-color, var(--color-primary));
    }

    &[data-readonly] {
      cursor: default;
    }

    &[data-disabled] {
      pointer-events: none;
    }

    &:focus-visible {
      outline: var(--rating-focus-ring-width, var(--border-width-sm)) solid
        var(--rating-focus-ring-color, var(--color-ring));
      outline-offset: var(--rating-focus-ring-offset, 0.125rem);
    }

    &[data-filled] .icon {
      fill: currentColor;
    }
  }

  .icon {
    width: var(--_rating-icon-size, var(--rating-icon-size-md, 1.25rem));
    height: var(--_rating-icon-size, var(--rating-icon-size-md, 1.25rem));
    fill: transparent;
    stroke: currentColor;
    transition:
      fill var(--rating-transition, var(--transition-default)),
      stroke var(--rating-transition, var(--transition-default));
  }
}
